                            </td>
                        </tr>
                        <tr v-if="filteredList.length === 0" class="empty_row">
                            <td colspan="10" class="text-center py-4">
                                <mdb-icon icon="inbox" class="mb-2" style="font-size: 48px; color: #ccc;"/>
