<script>
import {mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
import { mapGetters, mapActions } from 'vuex';
export default {
    components: {
        mdbInput, mdbBtn, mdbIcon,
    },
    data() {
        return {
            search: '',
            loading: false,
            Start_time: null,
            End_time: null,
            rashshod_list: [],
        }
    },
    async mounted () {
        let time1 = new Date();
        this.Start_time = time1.toISOString().slice(0,10);
        this.End_time = time1.toISOString().slice(0,10);
        await this.updateList();
    },
    computed: {
        ...mapGetters(['get_tarozi_tortilgan_list']),
        filteredList() {
            let list = this.rashshod_list || [];
            
            // Search filter
            if (this.search && this.search.trim() !== '') {
                const searchLower = this.search.toLowerCase();
                list = list.filter(row => {
                    const shafyorName = (row.shafyor_name || '').toLowerCase();
                    const carNumber = (row.car_number || '').toLowerCase();
                    const phone = (row.shafyor_tel || '').toLowerCase();
                    const product = (row.text_1 || '').toLowerCase();
                    const note = (row.note || '').toLowerCase();
                    
                    return shafyorName.includes(searchLower) ||
                           carNumber.includes(searchLower) ||
                           phone.includes(searchLower) ||
                           product.includes(searchLower) ||
                           note.includes(searchLower);
                });
            }
            
            return list;
        }
    },
    methods: {
        ...mapActions(['fetchTarozi_list']),
        async enter_invoice_new(invoice_id){
            this.$router.push('add_rashshod_bulgan/' + invoice_id)
        },
        async updateList(){ 
            let b_date  = this.Start_time + 'T00:00:35.000Z';
            let e_date  = this.End_time + 'T23:59:35.000Z';
            try{
                this.loading = true;
                const res = await fetch(this.$store.state.hostname + '/TegirmonInvoiceNews/getPaginationRashshodBulganlarList?page=0&size=1000&b_date=' + b_date + '&e_date=' + e_date);
                const data = await res.json();
                this.loading = false;
                console.log(data)
                if(res.status == 200 || res.status == 201){
                    this.rashshod_list = data.items_list || [];
                }
                else{
                    if(this.$refs.message) {
                        this.$refs.message.error('network_ne_connect')
                    }
                    this.loading = false; 
                }
                this.loading = false;
            }
            catch{
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect')
                }
                this.loading = false;
            }
        },
        formatNumber(num) {
            if (!num) return '0';
            return parseFloat(num).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
        },
        formatDate(dateString) {
            if (!dateString) return '-';
            return dateString.slice(8,10) + '-' + dateString.slice(5,7) + '-' + dateString.slice(0,4);
        },
        formatTime(dateString) {
            if (!dateString) return '';
            return dateString.slice(11,16);
        }
    },
}
</script>

